sql:
SELECT week_start_date, mean_distance_7days AS average_distance_travelled
FROM weekly_mobility_summary
ORDER BY week_start_date;

SELECT patient_id, AVG(mean_distance_7days) AS average_distance_per_week
FROM weekly_mobility_summary
GROUP BY patient_id;

SELECT AVG(metric_value) AS average_blood_pressure
FROM health_metrics
WHERE metric_name = 'Blood Pressure';

SELECT max_distance_7days AS max_distance
FROM weekly_mobility_summary
WHERE patient_id = 1;

SELECT patient_id, mean_distance_7days
FROM weekly_mobility_summary
ORDER BY mean_distance_7days DESC;

SELECT p.patient_name, wms.max_distance_7days
FROM weekly_mobility_summary wms
JOIN patients p ON wms.patient_id = p.patient_id;

external_knowledge:
- 'affected guys' refers to male patients; 
- 'joint pain' refers to the medical condition 'Arthritis'; 
- 'sugar issues' refers to the medical condition 'Diabetes';
- 'the spring month' refers to April 2023;
- 'average distances they covered in a week' refers to the mean distance traveled over 7 days.
